var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"안녕하세요...... 시청자 여러분......","JPN":"こんにちは……視聴者の皆さん……","ENG":"Hello, everyone...","TWN":"各位觀眾朋友們……大家好……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"오늘은 주말 컨텐츠로 일일 아르바이트를 진행하게 됐어요.","JPN":"今日は、週末の特別コンテンツとして、一日バイトをする配信を行うことになったんです。","ENG":"As a weekend special, I'll be taking on a part time job today.","TWN":"今天是以一日打工為主題的週末特輯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그래서 요즘 유명세를 타고 있는 카페 스트레가의 일일 종업원으로 일해볼 거에요.","JPN":"というわけでして、最近バズってるというこのカフェストレガの一日従業員として働こうと思います。","ENG":"So I'll try working as a one-day staff member at Cafe Strega, which has been getting very popular these days.","TWN":"所以，我要在最近很紅的史特雷加咖啡廳，當一天的服務生。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그럼...... 안녕하세요! 점장님!","JPN":"ええっと……おはよう…ございます……！　店長さん！","ENG":"Alright then... Hello, Ms. Manager!","TWN":"那就……妳好！店長！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"어려울 거 없어. 주방에서 대기하다가 주문 들어오면 레시피대로 만들기만 하면 돼.","JPN":"そう緊張せずともよい。汝は厨房に控え、注文が入ればレシピ通りに作るだけでよいのだ。","ENG":"There's nothing difficult, really. Just stand by in the kitchen and follow the recipe when we get new orders.","TWN":"沒什麼難的，只要在廚房裡等訂單過來，然後照著食譜做就可以了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"간단하지? 그럼 고생하라고.","JPN":"な？　簡単であろう？　では、頑張りたまえよ。","ENG":"Easy, right? Good luck.","TWN":"很簡單吧？那就交給妳了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네......! 맡겨만 주...... 앗......","JPN":"はい……！　お任せくださ……あっ……","ENG":"Okay! You can count on— Oh?","TWN":"好的……！交給我……啊……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"벌써 가버리셨네요. ......괜찮겠죠?","JPN":"もう行っちゃいました。……きっと大丈夫ですよね？","ENG":"She's already gone. I hope... I'll be alright.","TWN":"這麼快就走掉了，應該沒問題吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으음...... 왠지 이 가게 레시피는...... 독특한 것 같아요.","JPN":"うーん……このお店のレシピって何だか……独特な気がします。","ENG":"Hmm... The recipe here... seems rather interesting...","TWN":"嗯……總覺得這家店的食譜……很獨特呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맛있어지는 묘약 한 방울</color>이라는 재료가 온 메뉴에 들어가 있어요.","JPN":"<color=#ffd34c>美味しくなる妙薬を一滴</color>という材料が全部のメニューに入ってるんです。","ENG":"Here it mentions an ingredient called <color=#ffd34c>one drop of elixir of deliciousness</color> in the recipe.","TWN":"整個菜單的餐點都有一種叫做<color=#ffd34c>讓東西變美味的藥水一滴</color>的材料。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"비법소스 같은 거겠죠?! 아마......","JPN":"秘伝のソースか何かですよね！？　きっと……","ENG":"I guess it must be some kind of a secret sauce! I think...","TWN":"這是秘製醬料吧？！大概……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"일이 끝나고 나면, 미야도 조금만 나눠달라고 해볼래요!","JPN":"お仕事が終わったら、ミヤにも少し分けてくださいってお願いしてみます！","ENG":"I should see if I can get some once I'm done with my job here!","TWN":"工作結束後，米婭也跟店長要一點好了！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아! 첫 주문이에요.","JPN":"あっ！　最初の注文が入りました。","ENG":"Oh! Here's my first order.","TWN":"啊！第一份訂單來了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이건 그러니까......","JPN":"えっと、これは……","ENG":"Let's see...","TWN":"所以這是……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"인페르노 돈까스......?","JPN":"インフェルノ・トンカツ……？","ENG":"Inferno pork chops?","TWN":"地獄豬排……？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"안녕~ 요리 가지러 왔는데, 지금 상황이 어때?","JPN":"やっほ～。料理を取りに来たよ、今どんな感じ？","ENG":"Hi! I came to pick up the order. How's it going?","TWN":"妳好～我來拿料理了，狀況怎麼樣了？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"콜록, 콜록! 지금 막 완성했어요.","JPN":"ケホッ！　ケホッ！　たった今完成しました。","ENG":"*Cough, cough* I just finished making it.","TWN":"咳咳，咳咳！我正好完成了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그런데...... 괜찮은 건가요? 사람이...... 이런 걸 먹어도?","JPN":"でも……大丈夫なんでしょうか？　人間が……こんなの食べちゃっても？","ENG":"By the way, is that safe? I mean, to eat?","TWN":"可是……這沒問題嗎？客人……吃了這種東西不會有事嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"괜찮지 않을까? 난 먹어본 적 없어서 모르겠지만......","JPN":"大丈夫なんじゃな～い？　私は食べたことないから知らないけど……","ENG":"I'm sure it's okay. Although, I've never tried it myself...","TWN":"不會有事吧？雖然我沒吃過，所以不太清楚……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"라우라 말로는 그런 고통을 즐기는 변ㅌ...... 아니, 손님도 많이 있다나 봐!","JPN":"ラウラから聞いたわ。そういう苦痛を楽しむヘンタ……じゃなくて、お客様がたくさんいるみたいよ！","ENG":"According to Laura, there are plenty of perver—I mean, customers, who like their dishes extra hot!","TWN":"不過用蘿拉的話來說，似乎會有很多享受痛苦的變ㄊ……不是，我是說客人！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아, 참고로 그 요리를 할 때는 마스크와 고글을 꼭 쓰도록 해!","JPN":"あっ、ちなみに、その料理を作るときはマスクとゴーグルは必須だからね！","ENG":"Oh, by the way, be sure to put on a mask and goggles when you make that dish!","TWN":"啊，順便說一下，做那個料理一定要戴口罩和護目鏡！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......이미 늦은 것 같지만.","JPN":"……もう遅かったみたいだけど。","ENG":"Although I guess it's too late now...","TWN":"……雖然已經太遲了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으으, 아직도 눈이 따끔거려요.","JPN":"うう、まだ目がチクチクします。","ENG":"Ow... My eyes are still stinging.","TWN":"嗚嗚，我的眼睛還是好痛。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"제가 만들었다고는 하지만 이건 화학무기라고 해도 믿을 정도에요.","JPN":"自分で作っておいて何ですけど、これは化学兵器だと言われても信じちゃいそうです。","ENG":"I may have made it, but if someone told me it's a chemical weapon, I'd believe them.","TWN":"雖然是我做的，但說那道菜是生化武器我也相信。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"침식체도 이 냄새를 맡는다면 놀라서 도망치지 않을까요......?","JPN":"侵食体だって、この臭いを嗅いだら驚いて逃げちゃうんじゃないでしょうか……？","ENG":"The smell of this could even scare a C.O. away, I bet...","TWN":"侵蝕體聞到這個味道，會不會被嚇到逃跑啊……？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으음......","JPN":"んんー……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"역시 궁금해서 안되겠어요! 대체 누가 이런 걸 주문한 건지 직접 확인해봐야......","JPN":"やっぱりどうしても気になります！　いったい誰がこんなものを注文したのか確かめないと……","ENG":"That's it. I can't help it! I have to see who ordered something like this!","TWN":"我實在好奇到不行！我得親眼去看看到底是誰點的……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냠...... 역시 이 집 돈까스가 세상에서 제일 매콤하고 맛있다냥.","JPN":"パク……やっぱりこのお店のトンカツが世界で一番辛くて美味しいにゃ。","ENG":"*Nom* They make the spiciest, tastiest pork chops here.","TWN":"嚼嚼……果然這家店的豬排才稱得上是世界最辣最好吃的豬排喵。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"음? 미야가 왜 주방에서 나오는 거냥?","JPN":"ん？　何でミヤが厨房から出てくるのにゃ？","ENG":"Huh? Why are you coming out of the kitchen, Miya?","TWN":"咦？米婭妳為什麼會從廚房出來喵？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이, 일일 아르바이트 중인데...... 보미는 여기 어쩐 일이야?","JPN":"い、一日従業員としてバイトを……ボミこそ、どうしたの？","ENG":"I, uh... I'm working here for the day. What brings you here, Bomi?","TWN":"我、我在一日打工中……普美才是，妳來這裡做什麼？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그야 맛있는 걸 먹으러...... 냣?","JPN":"そりゃ、美味しいものを食べに……にゃっ？","ENG":"To have something tasty, of course. Meow?","TWN":"當然是來吃東西啦……喵？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"왜 갑자기 휴대폰을 뒤로 감추고 그래?","JPN":"何でスマホをささっと後ろに隠すのにゃ？","ENG":"Why are you hiding your phone all of a sudden?","TWN":"妳為什麼突然把手機藏到背後？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그, 그게......","JPN":"そ、それは……","ENG":"W-well...","TWN":"因、因為……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DONATION_VOICE_NULL_NULL","text":{"KOREA":"침식체도 싫어하는 화학무기를 누구보다 맛있게 먹을 줄 아는 보미! 대단해!","JPN":"侵食体も裸足で逃げる化学兵器をペロリと平らげてしまうボミ！　そこにシビれちゃう！","ENG":"Bomi thinks the C.O. repelling chemical weapon is delicious! Impressive!","TWN":"這種連侵蝕體都不敢靠近的化學武器，普美竟然吃得津津有味！太厲害了！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"응? 화학무기? 그게 무슨 소리냥?","JPN":"えっ？　化学兵器？　いったいどういうことにゃ？","ENG":"Hm? Chemical weapon? What's that supposed to mean?","TWN":"嗯？化學武器？你們在說什喵？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아앗, 자, 잠깐, 스 스피커가 켜져 있었네......","JPN":"あぁっ、ま、待って、ス、スピーカーがつけっぱなしになってたみたい……","ENG":"Oh, oops... The s-speaker was on...","TWN":"啊，等，等一下，喇叭還開著呢……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"보미야! 나...... 나 주문이 밀려서...... 나중에 봐!","JPN":"ボミ！　い……今、注文がたまってて……またあとでね！","ENG":"Bomi! I... I'm running behind on the orders... I'll see you later!","TWN":"普美！我……我這邊又有人點餐了……待會見！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하......","JPN":"にゃは……","ENG":"Meow...","TWN":"喵哈……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"......가끔 드는 생각이지만, 미야는 정말 엉뚱한 아이 같다냥.","JPN":"……時々思うけど、ミヤはホント不思議な子だにゃ。","ENG":"Sometimes I can't help but think how strange Miya really is... Meow.","TWN":"……偶爾覺得米婭真是個奇怪的孩子喵。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};